// The synthetic postcondition has the shape
//   (ensures_for(post1_netc, r1) && ensures_for(post2_netc, r2))
//   ==> det_send_packet_seq_equal(r1, r2, post1_netc, post2_netc).
// The previous attempt asserted conjuncts of the antecedent as if they
// were unconditional facts, which Verus rightly rejected (they live on
// the LHS of an `==>`, not in the proof context). We instead gate the
// whole antecedent with an `if`: in the `then` branch the conjuncts are
// in scope as hypotheses, so the inner asserts are discharged; in the
// `else` branch the implication is trivially true.

// Bind the ghost net-event sequences so their shape matches the
// `let (ok, Ghost(net_events)) = ...` pattern used by the synthetic
// ensures, giving the per-run `forall|i|` quantifiers a stable trigger
// term across both runs (n1[i] / n2[i]).
let n1: Seq<NetEvent> = (r1.1)@;
let n2: Seq<NetEvent> = (r2.1)@;

if (post1_netc.my_end_point() == pre_netc.my_end_point())
    && (post1_netc.ok() <==> r1.0)
    && (r1.0 ==> post1_netc.history() == pre_netc.history() + n1)
    && (r1.0 ==> send_log_entries_reflect_packets(n1, cpackets@))
    && (r1.0 ==> only_sent_marshalable_data(n1))
    && (forall|i: int| 0 <= i < n1.len() ==> n1[i] is Send)
    && (post2_netc.my_end_point() == pre_netc.my_end_point())
    && (post2_netc.ok() <==> r2.0)
    && (r2.0 ==> post2_netc.history() == pre_netc.history() + n2)
    && (r2.0 ==> send_log_entries_reflect_packets(n2, cpackets@))
    && (r2.0 ==> only_sent_marshalable_data(n2))
    && (forall|i: int| 0 <= i < n2.len() ==> n2[i] is Send)
{
    // Cross-run consequence of the two `my_end_point` conjuncts:
    // both equal pre_netc.my_end_point(), hence each other.
    assert(post1_netc.my_end_point() == post2_netc.my_end_point());

    // Re-trigger the per-run `forall|i|` quantifiers on n1/n2 so that
    // any per-index `is Send` lookup needed downstream has a matching
    // SMT instance ready, instead of being buried behind disjoint
    // trigger shapes from the two ensures clauses.
    assert forall|i: int| 0 <= i < n1.len() implies n1[i] is Send by {};
    assert forall|i: int| 0 <= i < n2.len() implies n2[i] is Send by {};

    // Materialise the per-run history equalities under their `ok`
    // hypotheses; this puts `post1_netc.history() == pre_netc.history() + n1`
    // (and the n2 analogue) into the proof context with a concrete
    // trigger shape rather than as a buried `==>` inside the antecedent.
    if r1.0 {
        assert(post1_netc.history() == pre_netc.history() + n1);
    }
    if r2.0 {
        assert(post2_netc.history() == pre_netc.history() + n2);
    }
}
